import{_ as l,c as i,o as a,V as e}from"./chunks/framework.9b555ede.js";const m=JSON.parse('{"title":"前端工程化","description":"","frontmatter":{},"headers":[],"relativePath":"original/【设计】工程化思路.md","filePath":"original/【设计】工程化思路.md","lastUpdated":1645753949000}'),t={name:"original/【设计】工程化思路.md"},r=e('<h1 id="前端工程化" tabindex="-1">前端工程化 <a class="header-anchor" href="#前端工程化" aria-label="Permalink to &quot;前端工程化&quot;">​</a></h1><h3 id="什么是工程化" tabindex="-1">什么是工程化 <a class="header-anchor" href="#什么是工程化" aria-label="Permalink to &quot;什么是工程化&quot;">​</a></h3><p>工程化， 就是一切能提高开发效率，提升代码质量，使工作流清晰，使开发人员体验更好的工具和手段。 前端项目工程化后，有下面几个特点：</p><ul><li>开发流程清晰，易操作，自动化构建部署</li><li>开发效率快，代码质量高</li><li>模块化、组件化、规范化</li></ul><h3 id="初始搭建-脚手架" tabindex="-1">初始搭建-脚手架 <a class="header-anchor" href="#初始搭建-脚手架" aria-label="Permalink to &quot;初始搭建-脚手架&quot;">​</a></h3><ul><li>多子项目（monorepo + larn + pnpm）</li><li>确定主体框架（vue、react、angular...）</li><li>打包工具（vite、webpack、rollup...）</li><li>css 管理（windicss、less、scss...）</li><li>husky + commitlint + lint-staged git 提交规则校验</li><li>eslint 代码质量检测 （定制适合项目团队的编码规则）</li><li>搭建 mock 服务</li><li>配置环境变量，实现一套代码多环境运行</li><li>引入单元测试</li><li>错误边界处理</li><li>错误路由页面引导</li><li>懒加载配置</li><li>移动端：弱网环境的骨架屏</li></ul><h3 id="构建打包" tabindex="-1">构建打包 <a class="header-anchor" href="#构建打包" aria-label="Permalink to &quot;构建打包&quot;">​</a></h3><ul><li>代码分割(tree-shaking)</li><li>资源文件 hash 策略</li><li>兼容性 Babel</li><li>代码压缩</li><li>无障碍访问</li></ul><h3 id="自动化部署流水线" tabindex="-1">自动化部署流水线 <a class="header-anchor" href="#自动化部署流水线" aria-label="Permalink to &quot;自动化部署流水线&quot;">​</a></h3><ul><li>考虑不同环境的处理</li><li>安装依赖一致性，添加缓存提高安装速率</li><li>生产监测，对性能差、访问频率高的页面进行优化提速</li></ul><h3 id="pnpm" tabindex="-1">pnpm <a class="header-anchor" href="#pnpm" aria-label="Permalink to &quot;pnpm&quot;">​</a></h3><p><a href="https://www.pnpm.cn/cli/publish" target="_blank" rel="noreferrer">pnpm</a> 比 npm、yarn 更好 pnpm</p><ul><li>通过软连接，解决了依赖重复占用磁盘空间的问题</li><li>更干净的 node_modules，避免了“幽灵依赖”的风险（同级的 node_modules 中只会有同级的 package.json 中声明了的依赖）</li></ul><h3 id="webpack-常用配置" tabindex="-1">webpack 常用配置 <a class="header-anchor" href="#webpack-常用配置" aria-label="Permalink to &quot;webpack 常用配置&quot;">​</a></h3><ul><li>更精确的范围 loader rules</li><li>resolve.modules</li><li>导入语句尽量带上后缀</li><li>较大的三方库配置 CDN</li><li>压缩 css\\js</li><li>html-weboack-plugin 生成 html 文件，并配置压缩</li><li>tree</li></ul>',15),o=[r];function n(s,h,c,d,p,u){return a(),i("div",null,o)}const b=l(t,[["render",n]]);export{m as __pageData,b as default};
